import{_ as a,c as l,j as e,o as n}from"./chunks/framework.B0cMFUTE.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"diary/2024-11-06.md","filePath":"diary/2024-11-06.md","lastUpdated":1735059727000}'),r={name:"diary/2024-11-06.md"};function p(s,t,o,d,i,u){return n(),l("div",null,t[0]||(t[0]=[e("p",null,"最近心中压抑，许多事情导致心情烦躁，写下来发泄一下。",-1),e("p",null,"我最近对唐浩云太不满了，现在大创论文的修改只有我一个人，唐浩云整天跟她对象混，他学习、刷英语、陪对象，我呢，改论文，晚上快结束了才回来，改论文占的时间是真长，总感觉我的时间全被占了，他还能坐享其成。再就是奖学金的事儿，我本来想留着机会申请好读书奖学金，但是呢，他劝我申合作社的奖学金，行，我申，这没问题，但是申报合作社奖学金的名单一出，他也在里面，我真的不知道该怎么说他，你就想着把一等奖给我占了是吧，明知道你排名比我高，然后还让我跟你申同一个，劝的时候一句也不提你也申，朋友在最关键的阶段背刺是最可怕的。",-1),e("p",null,"感觉翰林要升天了，数模国一加国家奖学金，很难受，但还是祝福他，慢慢来吧，放平心态。",-1),e("p",null,"大二这一学年当数模协会会长的负面影响是真的大。收益仅仅是认识了少数老师，拿了一段经历和几个奖状，代价呢，太多太多了。花大量的时间在各种杂事儿上，做好了赵建平当没看见，做差了赵建平使劲喷你，还不断给你提要求，提的那些要求现实吗我就想问你，除了给你心理压力，还能有什么？真真切切地感受到人的精力是有限的，当精神长时间高度紧张的时候，人的状态会下降，当精力不集中到一件事情上的时候，人的精神会越发散乱、飘，刚开始的时候捧得越高，最后就对你越狠。这一年心态的变化非常大，大一下各方面成绩都非常好，高玲把我引进去，我什么都不知道，赵建平就光在那跟我说，也不举例子，从没体验过这些，一口就答应了，一入深渊便直接溺死了。其实刚开始对这个还不怎么消极，挺单纯的，但是随着唐浩云在旁边不断地骂法如克、同情我，这种消极的思潮也开始潜移默化地影响我了，再加上赵建平整天什么强者弱者什么高要求高水平，我渐渐地变的功利了，是的，在学习之外的地方非常功利，一种平常不显6的功利。当时有一次跟程文玉聊天的时候不小心说了一句比较轻视人的话，惹得程文玉指责我，这确实是我的不对，当时挺后悔的，并开始反思我出现这种思想的来源，最后锚定到了当协会会长这件事上。",-1),e("p",null,"我感觉在大二之前我是很单纯的，思想算是独树一帜吧，因为是从小到大摸爬滚打出来的，跟他们那种有兄弟姐妹、学校环境很好很轻松、高考省份压力小的不太一样，我本身算是坚强的又闭塞的，心里很多想法都不敢与其他人说，但是不会轻视人，这是真的，最多就是志向不一样，但是自大二当上这赵建平的提线木偶开始，能明显感觉到跟同学仿佛不是生活在同一个世界，别人能放松地学习，我喜欢学习，这是没错的，但是却无法学习，因为一下课还要去找赵建平然后挨批、还要去找某个老师签字、还要跟谁谁谁布置任务。学习的时候才是最静心、最放松地时候，这是真真切切的体会，前段时间申峻豪也跟我说这个感受，我真的笑了，与我的感受一模一样，但我看他思想挺开放，应该可以把握住吧。",-1),e("p",null,"现在大三了，才感觉做了学生一回，经过大二被捶打的一学年，对各种通知消息很反感，不太像看手机刷那些杂乱无章的消息，看手机最喜欢安安静静地看小说、看动漫。",-1),e("p",null,"如果大二没有冒失的当上这个会长，或许我还是喜欢新大数院的吧，只有深入其中才知道它的千疮百孔。或许我已经减肥成功了，或许我已经学了不少东西了吧。呵呵，上健身课的时候，还得时时刻刻地看消息，提心吊胆的，也是没谁了。",-1),e("p",null,"总之，好好准备这周日的数竞以及下个月的英语六级吧。",-1)]))}const m=a(r,[["render",p]]);export{_ as __pageData,m as default};
